    "href": "/playbook/interview-scorecards",
    "category": "Operational Playbook",
    "content": "return ( ); \"use client\"; interface PlaybookPageLayoutProps children: ReactNode; : PlaybookPageLayoutProps) return ( /* Content */ children /* Footer */ ); // ✅ Server Component by default [ number: 1, title: \"Operations Coordinator Scorecard\", criteria: [ name: \"Client Communication\", description: \"Clear, professional, responsive\", , name: \"Project Management\", description: \"Organized, tracks tasks, meets deadlines\", , name: \"Problem Solving\", description: \"Thinks ahead, finds solutions\", , name: \"GHL / Tech Aptitude\", description: \"Experience with CRMs, quick learner\", , name: \"Attention to Detail\", description: \"Catches errors, thorough work\", , name: \"Culture Fit (Core Values)\", description: \"Honest, direct, growth-minded\", , ], , number: 2, title: \"Marketing Specialist Scorecard\", criteria: [ name: \"Copywriting Skills\", description: \"Compelling, clear, on-brand writing\", , name: \"Funnel / Email Marketing\", description: \"Experience with sequences, automation\", , name: \"GHL / Marketing Tools\", description: \"GHL, email tools, landing page builders\", , name: \"Creativity & Design Sense\", description: \"Visual eye, Canva skills, brand sense\", , name: \"Task Management\", description: \"Organized, meets deadlines, proactive\", , name: \"Culture Fit (Core Values)\", description: \"Honest, direct, growth-minded\", , ], , number: 3, title: \"Web Developer Scorecard\", criteria: [ name: \"GHL Website Builder\", description: \"Experience building in GHL\", , name: \"HTML/CSS Skills\", description: \"Custom code, responsive design\", , name: \"Workflow / Automation\", description: \"GHL workflows, triggers, logic\", , name: \"Design Eye\", description: \"Clean layouts, UX sense, modern style\", , name: \"Problem Solving / Debugging\", description: \"Troubleshoots issues independently\", , name: \"Culture Fit (Core Values)\", description: \"Honest, direct, growth-minded\", , ], , ]; return ( /* Header Block */ Operations Playbook Interview Scorecards Role-Specific Evaluation Criteria /* Instructions */ Instructions: Rate each criterion 1-5. Calculate average. Recommend hire if average ≥ 3.5 AND no criterion below 2. /* Rating Scale - Chevron Arrows */ /* 1 - Poor */ 1 - Poor /* 2 - Below */ 2 - Below /* 3 - Meets */ 3 - Meets /* 4 - Exceeds */ 4 - Exceeds /* 5 - Exceptional */ 5 - Exceptional /* Scorecards */ scorecards.map((scorecard) => ( scorecard.number . scorecard.title /* Candidate Info */ Candidate: \" \" &nbsp; Date: \" \" &nbsp; Interviewer: \" \" &nbsp; /* Criteria Table */ Criterion What to Look For Score scorecard.criteria.map((criterion) => ( criterion.name criterion.description /5 )) TOTAL / AVERAGE / scorecard.criteria.length * 5 = /* Notes */ Notes: &nbsp; /* Recommendation */ Recommendation: \" \" \" \" Strong Hire \" \" Hire \" \" No Hire \" \" Strong No Hire )) /* Footer */ Owner: HR Coordinator ); interview scorecard hiring candidate evaluation assessment scoring interview questions rubric criteria"
